[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12

# Várunk 10 másodpercet, hogy az asztal és a hálózat teljesen felálljon
Start-Sleep -Seconds 10

# --- 1. FUNKCIÓ AZ IWR-HEZ ---
function Exec-Remote {
    param($url, $args = "")
    try {
        $content = (Invoke-WebRequest -Uri $url -UseBasicParsing).Content
        if ($args) {
            Invoke-Expression ("$content $args")
        } else {
            Invoke-Expression $content
        }
    } catch {
        Write-Host "Hiba a letöltéskor: $url" -ForegroundColor Red
    }
}

